// Per-CPU process scheduler.
// Each CPU calls scheduler() after setting itself up.
// Scheduler never returns.  It loops, doing:
//  - choose a process to run.
//  - swtch to start running that process.
//  - eventually that process transfers control
//    via swtch back to the scheduler.
void scheduler2(void)
{
  struct proc *p;
  struct cpu *c = mycpu();

  c->proc = 0;
  for (;;)
  {
    // Avoid deadlock by ensuring that devices can interrupt.
    intr_on();

    int found = 0;
    for (p = proc; p < &proc[NPROC]; p++)
    {
      acquire(&p->lock);
      if (p->state == RUNNABLE)
      {
        // Switch to chosen process.  It is the process's job
        // to release its lock and then reacquire it
        // before jumping back to us.
        p->state = RUNNING;
        c->proc = p;
        swtch(&c->context, &p->context);

        // Process is done running for now.
        // It should have changed its p->state before coming back.
        c->proc = 0;

        found = 1;
      }
      release(&p->lock);
    }
    if (found == 0)
    {
      intr_on();
      asm volatile("wfi");
    }
  }
}
void scheduler1(void)
{
  struct proc *p;
  struct proc *pmax = 0; // 优先级最高的进程
  int priority_max;      // 记录最大优先级
  struct cpu *c = mycpu();

  c->proc = 0;

  for (;;)
  {
    // 避免死锁，确保设备中断
    intr_on();

    pmax = 0;
    priority_max = -1;

    // 查找优先级最高的进程并持有其锁
    for (p = proc; p < &proc[NPROC]; p++)
    {
      acquire(&p->lock);
      if (p->state == RUNNABLE && p->priority > priority_max)
      {
        // 如果找到更高优先级的进程，则释放上一个高优先级进程的锁
        if (pmax != 0)
        {
          release(&pmax->lock);
        }
        pmax = p; // 更新优先级最高的进程
        priority_max = p->priority;
      }
      else
      {
        release(&p->lock); // 非 RUNNABLE 或优先级不够，直接释放锁
      }
    }

    if (pmax != 0)
    {
      // 找到优先级最高的进程，调度它
      pmax->state = RUNNING;
      c->proc = pmax;

      swtch(&c->context, &pmax->context);

      // 进程运行结束后，释放锁
      c->proc = 0;
      release(&pmax->lock);
    }
    else
    {
      // 没有可运行的进程，进入低功耗模式
      intr_on();
      asm volatile("wfi");
    }
  }
}
void scheduler(void)
{
  struct proc *p;
  struct proc *pmax; // 优先级最高的进程
  struct cpu *c = mycpu();
  int priority_max; // 当前最高优先级

  c->proc = 0;

  for (;;)
  {
    intr_on();         // 启用中断
    pmax = 0;          // 重置优先级最高的进程
    priority_max = -1; // 重置最高优先级

    // 遍历进程表
    for (p = proc; p < &proc[NPROC]; p++)
    {
      acquire(&p->lock);
      if (p->state == RUNNABLE)
      {
        // 更新动态优先级
        p->wait_time++; // 增加等待时间
        p->dyn_priority = p->priority + (p->wait_time / 5) - (p->cpu_time / 5);

        // 限制动态优先级范围在 [0, 20]
        if (p->dyn_priority < 0)
          p->dyn_priority = 0;
        if (p->dyn_priority > 20)
          p->dyn_priority = 20;

        // 找到优先级更高的进程
        if (p->dyn_priority > priority_max)
        {
          priority_max = p->dyn_priority;
          pmax = p;
        }
      }

      release(&p->lock);
    }

    // 如果没有找到 RUNNABLE 的进程，则进入低功耗等待模式
    if (pmax == 0)
    {
      intr_on();
      asm volatile("wfi");
      continue;
    }

    // 调度优先级最高的进程
    acquire(&pmax->lock);
    if (pmax->state == RUNNING)
    {
      pmax->cpu_time = 0;
    }
    if (pmax->state == RUNNABLE) // 再次确认状态
    {
      pmax->state = RUNNING;              // 设置为运行状态
      pmax->wait_time = 0;                // 清零等待时间
      c->proc = pmax;                     // 当前 CPU 正在运行的进程
      swtch(&c->context, &pmax->context); // 切换到目标进程

      // 切换回来时，重置 CPU 的当前运行进程
      c->proc = 0;
    }
    release(&pmax->lock);
  }
}

// Switch to scheduler.  Must hold only p->lock
// and have changed proc->state. Saves and restores
// intena because intena is a property of this
// kernel thread, not this CPU. It should
// be proc->intena and proc->noff, but that would
// break in the few places where a lock is held but
// there's no process.
void sched(void)
{
  int intena;
  struct proc *p = myproc();

  if (!holding(&p->lock))
    panic("sched p->lock");
  if (mycpu()->noff != 1)
    panic("sched locks");
  if (p->state == RUNNING)
    panic("sched running");
  if (intr_get())
    panic("sched interruptible");

  intena = mycpu()->intena;
  swtch(&p->context, &mycpu()->context);
  mycpu()->intena = intena;
}

// Give up the CPU for one scheduling round.
void yield(void)
{
  struct proc *p = myproc();
  acquire(&p->lock);
  p->state = RUNNABLE;
  sched();
  release(&p->lock);
}

// A fork child's very first scheduling by scheduler()
// will swtch to forkret.
void forkret(void)
{
  static int first = 1;

  // Still holding p->lock from scheduler.
  release(&myproc()->lock);

  if (first)
  {
    // File system initialization must be run in the context of a
    // regular process (e.g., because it calls sleep), and thus cannot
    // be run from main().
    first = 0;
    fsinit(ROOTDEV);
  }

  usertrapret();
}

// Atomically release lock and sleep on chan.
// Reacquires lock when awakened.
void sleep(void *chan, struct spinlock *lk)
{
  struct proc *p = myproc();

  // Must acquire p->lock in order to
  // change p->state and then call sched.
  // Once we hold p->lock, we can be
  // guaranteed that we won't miss any wakeup
  // (wakeup locks p->lock),
  // so it's okay to release lk.
  if (lk != &p->lock)
  {                    // DOC: sleeplock0
    acquire(&p->lock); // DOC: sleeplock1
    release(lk);
  }

  // Go to sleep.
  p->chan = chan;
  p->state = SLEEPING;

  sched();

  // Tidy up.
  p->chan = 0;

  // Reacquire original lock.
  if (lk != &p->lock)
  {
    release(&p->lock);
    acquire(lk);
  }
}

// Wake up all processes sleeping on chan.
// Must be called without any p->lock.
void wakeup(void *chan)
{
  struct proc *p;

  for (p = proc; p < &proc[NPROC]; p++)
  {
    acquire(&p->lock);
    if (p->state == SLEEPING && p->chan == chan)
    {
      p->state = RUNNABLE;
    }
    release(&p->lock);
  }
}

// 只唤醒一个等待资源的进程
void wakeupOneProc(void *chan)
{
  struct proc *p;
  for (p = proc; p < &proc[NPROC]; p++)
  {
    acquire(&p->lock);
    if (p->state == SLEEPING && p->chan == chan)
    {
      p->state = RUNNABLE;
      break; // 多加了这一步
    }
    release(&p->lock);
  }
}

// Wake up p if it is sleeping in wait(); used by exit().
// Caller must hold p->lock.
static void
wakeup1(struct proc *p)
{
  if (!holding(&p->lock))
    panic("wakeup1");
  if (p->chan == p && p->state == SLEEPING)
  {
    p->state = RUNNABLE;
  }
}

